1892‚Üífunction resolveApiBase(): string {
1893‚Üí  const explicit = process.env.NEXT_PUBLIC_API_BASE_URL?.trim();
1894‚Üí  if (explicit) {
1895‚Üí    const base = explicit.replace(/\/+$/, "");
1896‚Üí    // If server-side (inside Docker) and targeting localhost, swap to internal "backend" service
1897‚Üí    if (typeof window === "undefined" && (base.includes("localhost") || base.includes("127.0.0.1"))) {
1898‚Üí      return base.replace(/localhost|127\.0\.0\.1/, "backend");
1899‚Üí    }
1900‚Üí    return base;
1901‚Üí  }
1902‚Üí
1903‚Üí  if (typeof window !== "undefined") {
1904‚Üí    const host = window.location.hostname.toLowerCase();
1905‚Üí    if (host === "localhost" || host === "127.0.0.1") {
1906‚Üí      return "http://localhost:8000";
1907‚Üí    }
1908‚Üí  }
1909‚Üí
1910‚Üí  // Handle server-side inference when no environment variable is set
1911‚Üí  if (typeof window === "undefined") {
1912‚Üí    return "http://backend:8000";
1913‚Üí  }
1914‚Üí
1915‚Üí  // Safety fallback for Railway production when NEXT_PUBLIC_API_BASE_URL is missing.
1916‚Üí  return "https://backend-production-0e53.up.railway.app";
1917‚Üí}
1918‚Üí
1919‚Üíconst API_BASE = resolveApiBase();
